Here is a clean, fully de-obfuscated, and well-structured implementation of the physics simulation. 

The original code implements a 2D directed graph physics engine using **N-Body repulsion** between all nodes, **Hooke's Law springs** for connected edges, and a **particle emitter** system attached to the nodes.

### Clean Implementation

```javascript
/**
 * Graph Physics & Particle Simulation
 * Reconstructed from obfuscated source
 */

// --- Configuration & Constants ---
const MATH = {
    TWO_PI: 6.283,
    PHI: 1.618,
    HALF_SQRT2: 0.707
};

const CONFIG = {
    repulsion: 4000,           // Force pushing nodes apart
    springStiffness: 0.004,    // Default elasticity of links
    damping: 0.92,             // Velocity loss over time (friction)
    centerGravity: 0.0003,     // Pull towards center of the screen
    maxParticles: 40,          // Particle pool limit
    particleDecay: 0.04,       // Air resistance applied to particles
    cameraSmoothing: 0.06,     // Lerp amount for camera movement
    centerX: 400,              // 0x190
    centerY: 300               // 0x12c
};

// --- Data Structures ---

const nodes = [
    { id: 'hub',     label: 'hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: 'alpha',   label: 'alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: 'beta',    label: 'beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: 'gamma',   label: 'gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: 'Delta',   label: 'Delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: 'epsilon', label: 'epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

const edges = [
    { a: 'hub',   b: 'alpha',   restLength: 160, k: 0.006 },
    { a: 'hub',   b: 'beta',    restLength: 160, k: 0.005 },
    { a: 'hub',   b: 'gamma',   restLength: 170, k: 0.004 },
    { a: 'hub',   b: 'Delta',   restLength: 170, k: 0.004 },
    { a: 'hub',   b: 'epsilon', restLength: 180, k: 0.003 },
    { a: 'alpha', b: 'beta',    restLength: 200, k: 0.002 },
    { a: 'gamma', b: 'Delta',   restLength: 220, k: 0.002 },
    { a: 'beta',  b: 'epsilon', restLength: 200, k: 0.002 }
];

const particles = [];
let tickCount = 0;

const camera = { x: 400, y: 300, zoom: 1 };
const targetCamera = { x: 400, y: 300, zoom: 1 };

// Helper to find node references for edges
const getNodeById = (id) => nodes.find(node => node.id === id) || null;

// Resolve edge string IDs to actual object references once
const connectedEdges = edges.map(edge => ({
    ...edge,
    nodeA: getNodeById(edge.a),
    nodeB: getNodeById(edge.b)
})).filter(edge => edge.nodeA && edge.nodeB);


// --- Core Systems ---

function updatePhysics() {
    // 1. N-Body Repulsion (Nodes push each other away)
    for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
            const n1 = nodes[i];
            const n2 = nodes[j];

            const dx = n1.x - n2.x;
            const dy = n1.y - n2.y;
            const dist = Math.sqrt(dx * dx + dy * dy) || 1;

            const force = CONFIG.repulsion / (dist * dist);
            const fx = (dx / dist) * force;
            const fy = (dy / dist) * force;

            n1.vx += fx;
            n1.vy += fy;
            n2.vx -= fx;
            n2.vy -= fy;
        }
    }

    // 2. Hooke's Law Springs (Edges pull/push towards rest length)
    for (const edge of connectedEdges) {
        const { nodeA, nodeB, restLength, k } = edge;

        const dx = nodeB.x - nodeA.x;
        const dy = nodeB.y - nodeA.y;
        const dist = Math.sqrt(dx * dx + dy * dy) || 1;

        const extension = dist - restLength;
        const force = (k || CONFIG.springStiffness) * extension;

        const fx = (dx / dist) * force;
        const fy = (dy / dist) * force;

        nodeA.vx += fx;
        nodeA.vy += fy;
        nodeB.vx -= fx;
        nodeB.vy -= fy;
    }

    // 3. Euler Integration, Damping, & Global Gravity
    for (const node of nodes) {
        // Gravity pulling towards the center
        node.vx += (CONFIG.centerX - node.x) * CONFIG.centerGravity;
        node.vy += (CONFIG.centerY - node.y) * CONFIG.centerGravity;

        // Damping (Friction)
        node.vx *= CONFIG.damping;
        node.vy *= CONFIG.damping;

        // Apply velocity to position
        node.x += node.vx;
        node.y += node.vy;
    }
}

function spawnParticle() {
    if (particles.length >= CONFIG.maxParticles) return;

    // Pick a random node to emit a particle
    const sourceNode = nodes[Math.floor(Math.random() * nodes.length)];

    // Generate random radial velocity
    const angle = Math.random() * MATH.TWO_PI;
    const speed = 0.3 + Math.random() * MATH.HALF_SQRT2;

    particles.push({
        x: sourceNode.x,
        y: sourceNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: Math.max(800, Math.random() * 1200),
        size: 0.8 + (Math.random() * MATH.PHI * MATH.HALF_SQRT2)
    });
}

function updateParticles() {
    const dragMultiplier = 1 - (CONFIG.particleDecay * 0.125);

    // Iterate backwards for safe splicing
    for (let i = particles.length - 1; i >= 0; i--) {
        const p = particles[i];

        p.age++;
        if (p.age > p.maxAge) {
            particles.splice(i, 1);
            continue;
        }

        // Apply drag/air-resistance
        p.vx *= dragMultiplier;
        p.vy *= dragMultiplier;

        // Apply velocity
        p.x += p.vx;
        p.y += p.vy;
    }
}

function updateCamera() {
    // Smoothly interpolate (Lerp) camera towards the target
    camera.x += (targetCamera.x - camera.x) * CONFIG.cameraSmoothing;
    camera.y += (targetCamera.y - camera.y) * CONFIG.cameraSmoothing;
    camera.zoom += (targetCamera.zoom - camera.zoom) * CONFIG.cameraSmoothing;
}

// --- Main Loop ---

function loop() {
    updatePhysics();
    updateParticles();
    updateCamera();

    // Spawn a particle every 3rd tick
    if (tickCount % 3 === 0) {
        spawnParticle();
    }

    tickCount++;
}

// 16ms interval (~60 FPS)
setInterval(loop, 16);
